1	export interface QuoteItem {
2	  type: string;
3	}
4	
5	export interface QuoteInput {
6	  items: QuoteItem[];
7	  customer: { yearsWithMHPCO: number };
8	  isFollowUp: boolean;
9	}
10	
11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_RATE = 0.1;
13	const BLOCK_OF_3_PREMIUM = 60;
14	
15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	};
22	
23	export function quote(input: QuoteInput): number {
24	  let policyBase = 0;
25	
26	  const counts: Record<string, number> = {};
27	  for (const item of input.items) {
28	    counts[item.type] = (counts[item.type] || 0) + 1;
29	  }
30	
31	  for (const [type, count] of Object.entries(counts)) {
32	    if (count === 3) {
33	      policyBase += BLOCK_OF_3_PREMIUM;
34	    } else {
35	      policyBase += count * BASE_PREMIUM[type];
36	    }
37	  }
38	
39	  const policyPremium = policyBase + policyBase * FIRST_INSURANCE_RATE;
40	  return Math.ceil(policyPremium + PROCESSING_FEE);
41	}
42	
